(8, 'UALAIJ9517773802', 5, '{\"id\":10,\"uniqid\":\"G51I6MSD17768716\",\"user_id\":4,\"type\":\"{\\\"id\\\":3,\\\"uniqid\\\":\\\"VHVJUV4H17769431\\\",\\\"name\\\":\\\"Telegram Subscribe\\\",\\\"cost\\\":5647,\\\"earning\\\":5647,\\\"platform\\\":\\\"Telegram\\\",\\\"members\\\":474,\\\"status\\\":\\\"active\\\",\\\"updated\\\":\\\"2026-04-25 16:17:49\\\",\\\"date\\\":\\\"2026-04-23 12:19:45\\\"}\",\"limit\":10,\"proofs\":0,\"link\":\"https:\\/\\/www.facebook.com\\/share\\/p\\/1C5igku2uj\\/?mibextid=wwXIfr\",\"caption\":\"Someone just offered you $4k cash to build a website for them. No questions asked. No contract. \\\"Just make it work.\\\"\\r\\n\\r\\nTempting? Sure. $4k is $4k.\\r\\n\\r\\nBut here\'s the thing, when you write code, you own that logic. If that site ends up stealing people\'s info, running scams, or laundering money, your fingerprints are all over the commit history. Good luck explaining to a client or a judge, that \\\"I just built the software and nothing more.\\\"\\r\\n\\r\\nSo no, I won\'t build it. Not because I can\'t. Because I won\'t attach my name, my reputation, or my conscience to someone else\'s fraud.\\r\\n\\r\\nCode isn\'t neutral when the intent is criminal.\\r\\n#tech #techtips #techwithmartony #life #programmer #softwareengineer\",\"banner\":null,\"status\":\"active\",\"updated\":\"2026-04-26 20:09:26\",\"date\":\"2026-04-22 16:28:03\"}', '{\"Screenshot\":\" <a href=\\\"http:\\/\\/172.20.10.5\\/wenorgigs\\/public\\/tasks\\/proofs\\/rprjjfl817773802.png\\\" target=\\\"_blank\\\" class=\\\"c-primary no-select w-fit\\\">\\n                        View Screenshot\\n                        <svg xmlns=\\\"http:\\/\\/www.w3.org\\/2000\\/svg\\\" viewBox=\\\"0 0 256 256\\\" fill=\\\"CurrentColor\\\" height=\\\"15\\\" width=\\\"15\\\"><path d=\\\"M228,104a12,12,0,0,1-24,0V69l-59.51,59.51a12,12,0,0,1-17-17L187,52H152a12,12,0,0,1,0-24h64a12,12,0,0,1,12,12Zm-44,24a12,12,0,0,0-12,12v64H52V84h64a12,12,0,0,0,0-24H48A20,20,0,0,0,28,80V208a20,20,0,0,0,20,20H176a20,20,0,0,0,20-20V140A12,12,0,0,0,184,128Z\\\"><\\/path><\\/svg>\\n\\n                    <\\/a>\"}', NULL, 'approved', '2026-04-28 20:45:02', '2026-04-28 20:44:31'),
